/*
 * Option 2 benchmark — MATLAB Coder Support Package for PyTorch (R2026a)
 * C code generated by MATLAB Coder 26.1 via MLIR/TOSA lowering of .pt2 model.
 * Input: MATLAB [1x75x3] column-major (pre-transposed from row-major test input).
 */
#include <stdio.h>
#include <time.h>
#include "codegen_opt2/lstm_infer_opt2.h"
#include "codegen_opt2/lstm_infer_opt2_initialize.h"
#include "codegen_opt2/lstm_infer_opt2_terminate.h"
#include "../benchmark/shared_test_input.h"

#define N_WARMUP  50
#define N_RUNS   1000

int main(void)
{
    int predictions[75];
    int i, t, f;
    clock_t t0, t1;
    double total_ms, per_run_ms;
    float in1_colmaj[225];

    /* Transpose to MATLAB column-major [1x75x3]: in1[t + f*75] = shared[t][f] */
    for (t = 0; t < 75; t++)
        for (f = 0; f < 3; f++)
            in1_colmaj[t + f*75] = shared_test_input[t*3 + f];

    lstm_infer_opt2_initialize();

    for (i = 0; i < N_WARMUP; i++)
        lstm_infer_opt2(in1_colmaj, predictions);

    t0 = clock();
    for (i = 0; i < N_RUNS; i++)
        lstm_infer_opt2(in1_colmaj, predictions);
    t1 = clock();

    total_ms   = (double)(t1 - t0) / CLOCKS_PER_SEC * 1000.0;
    per_run_ms = total_ms / N_RUNS;

    printf("Option 2: MATLAB Coder (PyTorch Support Package, MLIR->C, R2026a)\n");
    printf("  Runs/warmup : %d / %d\n", N_RUNS, N_WARMUP);
    printf("  Total time  : %.4f ms\n", total_ms);
    printf("  Per run     : %.4f ms  (%.2f us)\n", per_run_ms, per_run_ms * 1000.0);
    printf("  Predictions [%d steps]: [", SHARED_SEQ_LEN);
    for (t = 0; t < SHARED_SEQ_LEN; t++)
        printf("%d%s", predictions[t], t < SHARED_SEQ_LEN - 1 ? " " : "]\n");

    lstm_infer_opt2_terminate();
    return 0;
}
